public class FormSubmitTest extends WicketTestCase { private NestedFormsPage page ; private NestableForm outerForm ; private NestableForm middleForm ; private NestableForm innerForm ; @ Before public void before ( ) { tester . startPage ( new NestedFormsPage ( ) ) ; page = ( NestedFormsPage ) tester . getLastRenderedPage ( ) ; outerForm = ( NestableForm ) page . get ( "outerForm" ) ; middleForm = ( NestableForm ) page . get ( "outerForm:middleForm" ) ; innerForm = ( NestableForm ) page . get ( "outerForm:middleForm:innerForm" ) ; } @ Test public void allFormsEnabledSubmitOuterForm ( ) { assertEnabledState ( true , true , true ) ; FormTester formTester = tester . newFormTester ( "outerForm" ) ; formTester . submit ( "submit" ) ; assertOnSubmitCalled ( true , true , true ) ; assertOnErrorCalled ( false , false , false ) ; assertSubmitOrder ( innerForm , middleForm , outerForm ) ; } private void assertSubmitOrder ( NestableForm ... forms ) { assertEquals ( "not submitted in expected order!" , joinIds ( forms ) , page . submitOrder ) ; } private String joinIds ( Component [ ] comps ) { String result = "" ; for ( Component component : comps ) { result += component . getId ( ) ; } return result ; } private void assertErrorOrder ( NestableForm ... forms ) { assertEquals ( "not onError'd in expected order!" , joinIds ( forms ) , page . errorOrder ) ; } @ Test public void allFormsEnabledSubmitMiddleForm ( ) { assertEnabledState ( true , true , true ) ; FormTester formTester = tester . newFormTester ( "outerForm:middleForm" ) ; formTester . submit ( "submit" ) ; assertOnSubmitCalled ( false , true , true ) ; assertOnErrorCalled ( false , false , false ) ; assertSubmitOrder ( innerForm , middleForm ) ; } @ Test public void allFormsEnabledSubmitInnerForm ( ) { assertEnabledState ( true , true , true ) ; FormTester formTester = tester . newFormTester ( "outerForm:middleForm:innerForm" ) ; formTester . submit ( "submit" ) ; assertOnSubmitCalled ( false , false , true ) ; assertOnErrorCalled ( false , false , false ) ; assertSubmitOrder ( innerForm ) ; } @ Test public void middleFormDisabledSubmitOuterForm ( ) { middleForm . setEnabled ( false ) ; assertEnabledState ( true , false , true ) ; FormTester formTester = tester . newFormTester ( "outerForm" ) ; formTester . submit ( "submit" ) ; assertOnSubmitCalled ( true , false , false ) ; assertOnErrorCalled ( false , false , false ) ; assertSubmitOrder ( outerForm ) ; } @ Test public void innerFormDisabledSubmitOuterForm ( ) { innerForm . setEnabled ( false ) ; assertEnabledState ( true , true , false ) ; FormTester formTester = tester . newFormTester ( "outerForm" ) ; formTester . submit ( "submit" ) ; assertOnSubmitCalled ( true , true , false ) ; assertOnErrorCalled ( false , false , false ) ; assertSubmitOrder ( middleForm , outerForm ) ; } @ Test public void submitDisabledOuterForm ( ) { outerForm . setEnabled ( false ) ; assertEnabledState ( false , true , true ) ; FormTester formTester = tester . newFormTester ( "outerForm" ) ; try { formTester . submit ( "submit" ) ; fail ( "Executing the listener on disabled component is not allowed." ) ; } catch ( ListenerInvocationNotAllowedException expected ) { ; } assertOnSubmitCalled ( false , false , false ) ; assertOnErrorCalled ( false , false , false ) ; } @ Test public void errorOnInnerFormSubmitOuterForm ( ) { assertEnabledState ( true , true , true ) ; causeValidationErrorAndSubmit ( "outerForm" , "middleForm:innerForm:first" ) ; assertOnSubmitCalled ( false , false , false ) ; assertOnErrorCalled ( true , true , true ) ; assertErrorOrder ( innerForm , middleForm , outerForm ) ; } @ Test public void errorOnMiddleFormSubmitOuterForm ( ) { assertEnabledState ( true , true , true ) ; causeValidationErrorAndSubmit ( "outerForm" , "middleForm:first" ) ; assertOnSubmitCalled ( false , false , false ) ; assertOnErrorCalled ( true , true , false ) ; assertErrorOrder ( middleForm , outerForm ) ; } @ Test public void errorOnMiddleFormSubmitMiddleForm ( ) { assertEnabledState ( true , true , true ) ; causeValidationErrorAndSubmit ( "outerForm:middleForm" , "first" ) ; assertOnSubmitCalled ( false , false , false ) ; assertOnErrorCalled ( false , true , false ) ; assertErrorOrder ( middleForm ) ; } @ Test public void errorOnInnerFormSubmitMiddleForm ( ) { assertEnabledState ( true , true , true ) ; causeValidationErrorAndSubmit ( "outerForm:middleForm" , "innerForm:first" ) ; assertOnSubmitCalled ( false , false , false ) ; assertOnErrorCalled ( false , true , true ) ; assertErrorOrder ( innerForm , middleForm ) ; } @ Test public void middleFormDisabledErrorOnOuterFormSubmitOuterForm ( ) { middleForm . setEnabled ( false ) ; assertEnabledState ( true , false , true ) ; causeValidationErrorAndSubmit ( "outerForm" , "first" ) ; assertOnSubmitCalled ( false , false , false ) ; assertOnErrorCalled ( true , false , false ) ; assertErrorOrder ( outerForm ) ; } @ Test public void errorOnInnerFormDisabledMiddleFormSubmitOuterForm ( ) { middleForm . setEnabled ( false ) ; assertEnabledState ( true , false , true ) ; causeValidationErrorAndSubmit ( "outerForm" , "middleForm:innerForm:first" ) ; assertOnSubmitCalled ( true , false , false ) ; assertOnErrorCalled ( false , false , false ) ; } private void assertEnabledState ( boolean isOuterFormEnabled , boolean isMiddleFormEnabled , boolean isInnerFormEnabled ) { assertEquals ( isOuterFormEnabled , outerForm . isEnabled ( ) ) ; assertEquals ( isMiddleFormEnabled , middleForm . isEnabled ( ) ) ; assertEquals ( isInnerFormEnabled , innerForm . isEnabled ( ) ) ; } private void assertOnErrorCalled ( boolean isOuterFormOnErrorCalled , boolean isMiddleFormOnErrorCalled , boolean isInnerFormOnErrorCalled ) { assertEquals ( isOuterFormOnErrorCalled , outerForm . onErrorCalled ) ; assertEquals ( isMiddleFormOnErrorCalled , middleForm . onErrorCalled ) ; assertEquals ( isInnerFormOnErrorCalled , innerForm . onErrorCalled ) ; } private void assertOnSubmitCalled ( boolean isOuterFormOnSubmitCalled , boolean isMiddleFormOnSubmitCalled , boolean isInnerFormOnSubmitCalled ) { assertEquals ( isOuterFormOnSubmitCalled , outerForm . onSubmitCalled ) ; assertEquals ( isMiddleFormOnSubmitCalled , middleForm . onSubmitCalled ) ; assertEquals ( isInnerFormOnSubmitCalled , innerForm . onSubmitCalled ) ; } private FormTester causeValidationErrorAndSubmit ( String formToBeSubmitted , String componentToGetError ) { FormTester formTester ; formTester = tester . newFormTester ( formToBeSubmitted ) ; formTester . setValue ( componentToGetError , "" ) ; formTester . submit ( "submit" ) ; return formTester ; } }